import Link from "next/link";
import type { ReactNode } from "react";
import { CursorExperience } from "./cursor-experience";
import { VisitTracker } from "./visit-tracker";
import { ThemeToggle } from "./theme-toggle";
import { ScrollControl } from "./scroll-control";
import { MobileMenu } from "./mobile-menu";
import { DesktopNav } from "./desktop-nav";
import { getSiteContent } from "@/lib/content-store";
import type { SiteSettings } from "@/lib/content-data";

const links = [
  ["Ana Sayfa", "/"], ["Kurumsal", "/kurumsal"], ["Hizmetler", "/hizmetler"], ["Projeler", "/projeler"],
  ["Makine Parkı", "/makine-parki"], ["Referanslar", "/referanslar"], ["İletişim", "/iletisim"],
];

export function SiteHeader({ settings }: { settings: SiteSettings }) {
  return (
    <header className="site-header">
      <Link href="/" className="brand" aria-label="Ulucan Hafriyat ana sayfa">
        <img className="brand-logo brand-logo-wide" src={settings.headerLogoUrl} alt="Ulucan Hafriyat" />
        <img className="brand-logo brand-logo-compact" src={settings.emblemLogoUrl} alt="Ulucan amblemi" />
      </Link>
      <DesktopNav links={links as Array<[string, string]>} />
      <ThemeToggle />
      <Link className="header-cta" href="/iletisim">Teklif Al <span aria-hidden="true">↗</span></Link>
      <MobileMenu links={links as Array<[string, string]>} />
    </header>
  );
}

export function SiteFooter({ settings }: { settings: SiteSettings }) {
  const socialLinks = [
    ["Instagram", settings.instagramUrl],
    ["Facebook", settings.facebookUrl],
    ["LinkedIn", settings.linkedinUrl],
    ["YouTube", settings.youtubeChannelUrl],
  ].filter((item): item is [string, string] => Boolean(item[1]));
  return (
    <footer className="site-footer">
      <div className="footer-lead">
        <p className="eyebrow light">Bir sonraki proje</p>
        <h2>Sağlam işler,<br />güvenilir ortaklıklar.</h2>
        <Link href="/iletisim" className="button button-light">Bizimle iletişime geçin <span>↗</span></Link>
      </div>
      <div className="footer-grid">
        <div><img className="footer-brand-logo" src={settings.headerLogoUrl} alt="Ulucan Hafriyat" /><p>Boğazköy İstiklal Mah.<br />Türksoy Cd. No:12<br />Arnavutköy · İstanbul</p></div>
        <div><strong>İletişim</strong><a href="tel:+902125979913">0212 597 99 13</a><a href="mailto:info@ulucanhafriyat.com">info@ulucanhafriyat.com</a></div>
        <div><strong>Bağlantılar</strong>{links.slice(0, 6).map(([label, href]) => <Link key={href} href={href}>{label}</Link>)}</div>
        {socialLinks.length > 0 && <div><strong>Sosyal Medya</strong>{socialLinks.map(([label, href]) => <a key={label} href={href} target="_blank" rel="noreferrer">{label} <span aria-hidden="true">↗</span></a>)}</div>}
        <div><strong>Çalışma Saatleri</strong><p>Hafta içi 09.00–18.00<br />Cumartesi 09.00–15.00</p></div>
      </div>
      <div className="footer-bottom"><span>© {new Date().getFullYear()} Ulucan Hafriyat</span><span><Link href="/gizlilik">Gizlilik ve KVKK</Link></span></div>
    </footer>
  );
}

export async function PageFrame({ children }: { children: ReactNode }) {
  const { settings } = await getSiteContent();
  return <><VisitTracker /><CursorExperience /><ScrollControl /><SiteHeader settings={settings} /><main>{children}</main><SiteFooter settings={settings} /></>;
}
